package be.schaubroeck.lpb.rkm.rekenmotor.bv;

import be.schaubroeck.lpb.rkm.rekenmotor.LoonElement;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenContext;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.MoneyKey;
import be.schaubroeck.lpb.rkm.rekenmotor.util.CheckRegime;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementChecker;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.verdeler.BedragVerdelerFactory;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.Persoon;
import lombok.AllArgsConstructor;
import org.joda.time.LocalDate;

import java.math.RoundingMode;
import java.util.Collection;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey.BELASTBAAR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_GEWONE_BEZOLDIGING_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_VERVANGINGS_INKOMEN_ZIEKTE_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONELEMENT_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.OPPER_LAATSTE_GEGEVENS_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKENTIJD_KEY;

@AllArgsConstructor
public class BvVoluntariaat {

    private static final LocalDate START_VERDELEN_OVER_DISPO = new LocalDate(2022, 1, 1);

    private LocalDate taxdatum;

    public Money bepaalGewoon(RekenContext opdrachtContext, Collection<LoonElement> loonElementen) {
        return bepaal(opdrachtContext, loonElementen, false);
    }

    public Money bepaalDispo(RekenContext opdrachtContext, Collection<LoonElement> loonElementen) {
        return bepaal(opdrachtContext, loonElementen, true);
    }

    private Money bepaal(RekenContext opdrachtContext, Collection<LoonElement> loonElementen, boolean dispo) {
        RekenTijd rekenTijd = opdrachtContext.getUnchecked(REKENTIJD_KEY);
        if (rekenTijd.beginDatum.isBefore(START_VERDELEN_OVER_DISPO)) {
            return bepaalOud(opdrachtContext, dispo);
        } else {
            return bepaalNieuw(opdrachtContext, loonElementen, dispo);
        }
    }

    private Money bepaalOud(RekenContext opdrachtContext, boolean dispo) {
        if (dispo) {
            return Money.ZERO;
        } else {
            Opper opperLaatsteGegevens = opdrachtContext.getUnchecked(OPPER_LAATSTE_GEGEVENS_KEY);
            return opperLaatsteGegevens.getOpdrachtFiscaliteit().getFiskaalVoluntariaat();
        }
    }

    private Money bepaalNieuw(RekenContext opdrachtContext, Collection<LoonElement> loonElementen, boolean dispo) {
        Money bbGewoon = BvTools.getBelastbaar(BEDRIJFSVOORHEFFING_GEWONE_BEZOLDIGING_KEY, BELASTBAAR_KEY, loonElementen, taxdatum);
        Money bbDispo60 = BvTools.getBelastbaar(BEDRIJFSVOORHEFFING_VERVANGINGS_INKOMEN_ZIEKTE_KEY, BELASTBAAR_KEY, loonElementen, taxdatum);
        Money totaal = bbGewoon.add(bbDispo60);
        Opper opperLaatsteGegevens = opdrachtContext.getUnchecked(OPPER_LAATSTE_GEGEVENS_KEY);
        Money voluntariaat = opperLaatsteGegevens.getOpdrachtFiscaliteit().getFiskaalVoluntariaat();
        if (totaal.signum() == 0) {
            return Money.ZERO;
        } else if (dispo) {
            //Dit is half_down omdat het half_up is bij de verdeling van het voluntariaat in bij Gewoon
            return voluntariaat.multiply(bbDispo60.divide(totaal)).round(2, RoundingMode.HALF_DOWN);
        } else {
            return voluntariaat.multiply(bbGewoon.divide(totaal)).round(2);
        }
    }


    public void minimaalVoluntariaat(RekenContext context) {
        Persoon persoon = context.getUnchecked(PERSOON_KEY);
        LoonElementManager manager = context.getUnchecked(LOONELEMENT_MANAGER_KEY);
        for (Opdracht opdracht : persoon.getOpdrachten()) {
            RekenContext opdrachtContext = context.getOpdrachtContext(opdracht);
            Collection<LoonElement> opdrachtElementen = manager.getOpdrachtsElementen(opdracht);

            Money voluntariaat = bepaalGewoon(opdrachtContext, opdrachtElementen);
            Money bvOpdracht = RekenTools.getSomProperty(BEDRIJFSVOORHEFFING_GEWONE_BEZOLDIGING_KEY, opdrachtElementen);
            if (bvOpdracht.compareTo(voluntariaat) < 0) {
                Money bbOpdracht = BvTools.getBelastbaar(BEDRIJFSVOORHEFFING_GEWONE_BEZOLDIGING_KEY, BELASTBAAR_KEY, opdrachtElementen, taxdatum);
                herverdeelBedrijfsvoorheffing(BEDRIJFSVOORHEFFING_GEWONE_BEZOLDIGING_KEY, voluntariaat, BELASTBAAR_KEY, bbOpdracht, opdrachtElementen);
            }
        }
    }

    protected void herverdeelBedrijfsvoorheffing(
            MoneyKey bvKey, Money bedrijfsvoorheffing, MoneyKey bbKey, Money totaalBelastbaar,
            Collection<LoonElement> loonElementen) {
        LoonElementChecker checkRegime = new CheckRegime(taxdatum, bvKey);
        BedragVerdelerFactory.verdeelBedragVolgensBasisPut(bvKey, bedrijfsvoorheffing, bbKey, totaalBelastbaar, loonElementen, checkRegime);
    }

}
